import sysfrom pathlib import Path# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import (    RAW_DATA_DIR,    INTERIM_DATA_DIR,    PROCESSED_DATA_DIR,    EXTERNAL_DATA_DIR,    LOG_DIR,    TABLE_DIR,    FIG_DIR,    PREDICTIONS_DIR,    REPORTS_DIR,    BASELINE_MODELS_DIR,    EMBEDDINGS_DIR,    FINAL_MODELS_DIR,)def main():    dirs = [        RAW_DATA_DIR,        INTERIM_DATA_DIR,        PROCESSED_DATA_DIR,        EXTERNAL_DATA_DIR,        LOG_DIR,        TABLE_DIR,        FIG_DIR,        PREDICTIONS_DIR,        REPORTS_DIR,        BASELINE_MODELS_DIR,        EMBEDDINGS_DIR,        FINAL_MODELS_DIR,    ]    for folder in dirs:        folder.mkdir(parents=True, exist_ok=True)        print(f"Created or already exists: {folder}")    print("\nProject folders are ready.")if __name__ == "__main__":    main()